import React, { useState } from 'react';

const COLS = ['A', 'B', 'C', 'D'];
const ROWS = [1, 2, 3, 4];

export default function Spreadsheet() {
  const [raw, setRaw] = useState({ A1: '10', B1: '20', C1: '=A1+B1', A2: '5', B2: '=A2*3', C2: '=B2+C1' });
  const [editing, setEditing] = useState(null);

  const safeEval = (e) => {
    if (!/^[-+*/(). 0-9]+$/.test(e)) return '#ERR';
    try {
      const r = Function(`"use strict";return (${e})`)();
      return Number.isFinite(r) ? r : '#ERR';
    } catch {
      return '#ERR';
    }
  };

  const evalCell = (id, seen) => {
    const guard = seen || new Set();
    if (guard.has(id)) return '#CYCLE';
    const v = raw[id] || '';
    if (!v.startsWith('=')) return v;
    const expr = v.slice(1).replace(/[A-Z]+[0-9]+/g, (ref) => {
      const val = evalCell(ref, new Set([...guard, id]));
      return typeof val === 'number' ? String(val) : String(val || 0);
    });
    return safeEval(expr);
  };

  const cellStyle = {
    width: 80,
    height: 30,
    border: '1px solid #cbd5e1',
    padding: '0 6px',
    boxSizing: 'border-box',
    fontSize: 14,
    textAlign: 'right',
  };

  return (
    <table style={{ borderCollapse: 'collapse' }}>
      <thead>
        <tr>
          <th style={{ ...cellStyle, background: '#f1f5f9' }}></th>
          {COLS.map((c) => (
            <th key={c} style={{ ...cellStyle, background: '#f1f5f9', textAlign: 'center' }}>{c}</th>
          ))}
        </tr>
      </thead>
      <tbody>
        {ROWS.map((r) => (
          <tr key={r}>
            <td style={{ ...cellStyle, background: '#f1f5f9', textAlign: 'center', fontWeight: 600 }}>{r}</td>
            {COLS.map((c) => {
              const id = `${c}${r}`;
              return (
                <td key={id} style={{ padding: 0 }} onClick={() => setEditing(id)}>
                  {editing === id ? (
                    <input
                      autoFocus
                      value={raw[id] || ''}
                      onChange={(e) => setRaw((m) => ({ ...m, [id]: e.target.value }))}
                      onBlur={() => setEditing(null)}
                      onKeyDown={(e) => e.key === 'Enter' && setEditing(null)}
                      style={{ ...cellStyle, outline: '2px solid #2563eb' }}
                    />
                  ) : (
                    <div style={{ ...cellStyle, lineHeight: '30px', cursor: 'cell', background: '#fff' }}>
                      {String(evalCell(id))}
                    </div>
                  )}
                </td>
              );
            })}
          </tr>
        ))}
      </tbody>
    </table>
  );
}

