### Step 1 — Raw map + editing
```js
const raw = reactive({ A1: '10', B1: '20', C1: '=A1+B1' });
const editing = ref(null);
```

### Step 2 — Recursive evaluation
```js
function evalCell(id, seen = new Set()) {
  if (seen.has(id)) return '#CYCLE';
  const v = raw[id] || '';
  if (!v.startsWith('=')) return v;
  const expr = v.slice(1).replace(/[A-Z]+[0-9]+/g, (ref) => evalCell(ref, new Set([...seen, id])));
  return safeEval(expr);
}
```

### Step 3 — Safe arithmetic
```js
const safeEval = (e) => /^[-+*/(). 0-9]+$/.test(e) ? Function(`return (${e})`)() : '#ERR';
```

### Step 4 — Edit shows raw
```vue
<input v-if="editing === id" v-model="raw[id]" @blur="editing = null" />
<div v-else @click="editing = id">{{ evalCell(id) }}</div>
