import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-spreadsheet',
  template: `
    <table style="border-collapse: collapse;">
      <thead>
        <tr>
          <th class="head"></th>
          <th *ngFor="let c of cols" class="head">{{ c }}</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let r of rows">
          <td class="head">{{ r }}</td>
          <td *ngFor="let c of cols" style="padding: 0;" (click)="editing = c + r">
            <input
              *ngIf="editing === (c + r)"
              [value]="raw[c + r] || ''"
              (input)="raw[c + r] = $any($event.target).value"
              (blur)="editing = null"
              (keydown.enter)="editing = null"
              class="cell editing"
            />
            <div *ngIf="editing !== (c + r)" class="cell">{{ evalCell(c + r) }}</div>
          </td>
        </tr>
      </tbody>
    </table>
  `,
  styles: [`
    table { border-collapse: collapse; }
    .cell, .head { width: 80px; height: 30px; border: 1px solid #cbd5e1; padding: 0 6px; box-sizing: border-box; font-size: 14px; text-align: right; }
    .cell { line-height: 30px; background: #fff; cursor: cell; }
    .cell.editing { outline: 2px solid #2563eb; }
    .head { background: #f1f5f9; text-align: center; font-weight: 600; }
  `],
})
export class SpreadsheetComponent {
  cols = ['A', 'B', 'C', 'D'];
  rows = [1, 2, 3, 4];
  editing: string | null = null;
  raw: Record<string, string> = { A1: '10', B1: '20', C1: '=A1+B1', A2: '5', B2: '=A2*3', C2: '=B2+C1' };

  safeEval(e: string): string | number {
    if (!/^[-+*/(). 0-9]+$/.test(e)) {
      return '#ERR';
    }
    try {
      const r = Function('"use strict";return (' + e + ')')();
      return isFinite(r) ? r : '#ERR';
    } catch (err) {
      return '#ERR';
    }
  }

  evalCell(id: string, seen = new Set<string>()): string | number {
    if (seen.has(id)) {
      return '#CYCLE';
    }
    const v = this.raw[id] || '';
    if (v.charAt(0) !== '=') {
      return v;
    }
    const next = new Set(seen);
    next.add(id);
    const expr = v.slice(1).replace(/[A-Z]+[0-9]+/g, (ref) => {
      const val = this.evalCell(ref, next);
      return typeof val === 'number' ? String(val) : String(val || 0);
    });
    return this.safeEval(expr);
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Mini Spreadsheet Demo</h1>
      <p style="color: #666;">Click a cell to edit. Try formulas like <code>=A1+B1</code>.</p>
      <app-spreadsheet></app-spreadsheet>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, SpreadsheetComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
